CREATE TABLE posting (posting_id UUID PRIMARY KEY, journal_entry_id UUID NOT NULL REFERENCES journal_entry(journal_entry_id), ledger_account_id UUID NOT NULL REFERENCES ledger_account(ledger_account_id), side CHAR(1) NOT NULL CHECK(side IN ('D','C')), currency CHAR(3) NOT NULL, minor_units BIGINT NOT NULL CHECK(minor_units > 0), sequence BIGINT NOT NULL CHECK(sequence > 0), UNIQUE(ledger_account_id, sequence));
